import boto3
import cfnresponse
from botocore.exceptions import ClientError

logs = boto3.client('logs')
appsync = boto3.client('appsync')

# Log group names to skip even if they match a prefix filter.
# Step Functions retention is managed by its own CFN template (14 days).
SKIP_PREFIXES = (
    '/aws/stepfunction/team-step-function/',
)

# Lambda log-group name prefixes (the part after '/aws/lambda/') that
# belong to this TEAM deployment. Each entry must end with '-<env>' or be
# matched as a prefix that includes '-<env>-' for Amplify auto-named ones.
LAMBDA_NAME_PREFIXES = (
    'team',                  # team*, Team* covered case-insensitively below
    'Team',
    'amplify-teamidcapp-',   # CFN-managed custom-resource Lambdas
)


def _iter_log_groups(prefix):
    paginator = logs.get_paginator('describe_log_groups')
    for page in paginator.paginate(logGroupNamePrefix=prefix):
        for lg in page.get('logGroups', []):
            yield lg


def _matches_team_lambda(short, env):
    suffix = '-' + env
    # team* / Team* funcs: '/aws/lambda/<func>-<env>'
    for p in ('team', 'Team'):
        if short.startswith(p) and short.endswith(suffix):
            return True
    # Amplify auto-named CFN custom-resource lambdas:
    # '/aws/lambda/amplify-teamidcapp-<env>-<id>-<Resource>-<rand>'
    if short.startswith('amplify-teamidcapp-' + env + '-'):
        return True
    # Bootstrap stack lambdas (deployment/template.yml) — auto-named:
    # '/aws/lambda/TEAM-IDC-APP-<Resource>-<rand>'
    if short.startswith('TEAM-IDC-APP-'):
        return True
    return False


def _team_lambda_log_groups(env):
    for lg in _iter_log_groups('/aws/lambda/'):
        name = lg['logGroupName']
        short = name[len('/aws/lambda/'):]
        if _matches_team_lambda(short, env):
            yield name


def _team_appsync_log_groups(env):
    api_name = 'team-' + env
    api_ids = []
    next_token = None
    while True:
        kwargs = {'maxResults': 25}
        if next_token:
            kwargs['nextToken'] = next_token
        resp = appsync.list_graphql_apis(**kwargs)
        for api in resp.get('graphqlApis', []):
            if api.get('name') == api_name:
                api_ids.append(api['apiId'])
        next_token = resp.get('nextToken')
        if not next_token:
            break
    for api_id in api_ids:
        prefix = '/aws/appsync/apis/' + api_id
        for lg in _iter_log_groups(prefix):
            yield lg['logGroupName']


def _put_retention(name, retention_days):
    try:
        logs.put_retention_policy(logGroupName=name, retentionInDays=retention_days)
        return True
    except ClientError as e:
        if e.response.get('Error', {}).get('Code') == 'ResourceNotFoundException':
            # Log group hasn't been auto-created yet (e.g. lambda never invoked).
            print('Skip (not yet created): ' + name)
            return False
        raise


def _apply(retention_days, env):
    applied = []
    seen = set()

    for name in _team_lambda_log_groups(env):
        if any(name.startswith(p) for p in SKIP_PREFIXES):
            continue
        if name in seen:
            continue
        if _put_retention(name, retention_days):
            applied.append(name)
            seen.add(name)

    for name in _team_appsync_log_groups(env):
        if name in seen:
            continue
        if _put_retention(name, retention_days):
            applied.append(name)
            seen.add(name)

    # Always (try to) cover this lambda's own log group, even if it
    # doesn't exist yet at describe-time on first run.
    self_lg = '/aws/lambda/team-log-retention-' + env
    if self_lg not in seen:
        if _put_retention(self_lg, retention_days):
            applied.append(self_lg)
            seen.add(self_lg)

    return applied


def handler(event, context):
    try:
        if event.get('RequestType') == 'Delete':
            cfnresponse.send(event, context, cfnresponse.SUCCESS, {'Data': 'Delete: noop'})
            return

        props = event.get('ResourceProperties', {}) or {}
        retention_days = int(props.get('retentionDays', 90))
        env = props.get('env', '')

        applied = _apply(retention_days, env)
        print('Applied retention {} days to {} log groups'.format(retention_days, len(applied)))
        for n in applied:
            print('  - ' + n)

        cfnresponse.send(
            event,
            context,
            cfnresponse.SUCCESS,
            {'Count': len(applied), 'RetentionDays': retention_days},
        )
    except Exception as e:
        print('Error: {}'.format(e))
        cfnresponse.send(event, context, cfnresponse.FAILED, {'Error': str(e)})
